#!/bin/bash
# Evaluate GRPO LoRA adapter vs base model (Qwen3-4B-Thinking-2507)
# on all 28 puzzle tasks using locally-served vLLM with --enable-lora.
#
# Output:  results/{DATE}_grpo_vs_base_qwen3_4b/{model_safe}/{task}/...
# Data:    data/jsonl/{DATE}/{task}.jsonl  (generated by scripts/gen/gen_for_grpo_eval.py)

set -e

RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
NC='\033[0m'

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
cd "$PROJECT_ROOT"

# ============ 설정 ============
DATE="${DATE:-$(date +%Y-%m-%d)}"
GPU_ID="${GPU_ID:-0}"
VLLM_PORT="${VLLM_PORT:-8000}"
VLLM_HOST="0.0.0.0"
REMOTE_URL="http://localhost:${VLLM_PORT}"
GEN_KWARGS="temperature=0.6,max_tokens=16384,top_p=0.95,top_k=20,reasoning=on"

BASE_MODEL="Qwen/Qwen3-4B-Thinking-2507"
LORA_NAME="grpo"
LORA_PATH="$PROJECT_ROOT/models/grpo/final"
LORA_RANK=64

DATA_DIR="data/jsonl/${DATE}"
RESULT_DIR="results/${DATE}_grpo_vs_base_qwen3_4b"

# Both identifiers point to the same vLLM server; vLLM picks base vs LoRA by name.
MODELS=(
    "$BASE_MODEL"
    "$LORA_NAME"
)

TASKS=(
    "array_formula_en" "array_formula_ko"
    "causal_dag_en"    "causal_dag_ko"
    "cipher_en"        "cipher_ko"
    "cryptarithmetic_en" "cryptarithmetic_ko"
    "ferryman_en"      "ferryman_ko"
    "hanoi_en"         "hanoi_ko"
    "inequality_en"    "inequality_ko"
    "kinship"          "kinship_vision"
    "logic_grid_en"    "logic_grid_ko"
    "minesweeper_en"   "minesweeper_ko"
    "number_baseball_en" "number_baseball_ko"
    "sat_puzzles_en"   "sat_puzzles_ko"
    "sudoku_en"        "sudoku_ko"
    "yacht_dice_en"    "yacht_dice_ko"
)
# ==============================

VENV_ACTIVATE="$PROJECT_ROOT/.venv/bin/activate"
if [ ! -f "$VENV_ACTIVATE" ]; then
    echo -e "${RED}Error: .venv not found at $PROJECT_ROOT/.venv${NC}"
    exit 1
fi
source "$VENV_ACTIVATE"

if [ ! -d "$DATA_DIR" ]; then
    echo -e "${RED}Error: data dir not found: $DATA_DIR${NC}"
    echo -e "${YELLOW}Run scripts/gen/gen_for_grpo_eval.py first.${NC}"
    exit 1
fi

if [ ! -d "$LORA_PATH" ]; then
    echo -e "${RED}Error: LoRA adapter not found: $LORA_PATH${NC}"
    exit 1
fi

mkdir -p "$RESULT_DIR"

start_vllm_server() {
    echo -e "${BLUE}Starting vLLM server: ${BASE_MODEL} (+ LoRA '${LORA_NAME}') on GPU ${GPU_ID}...${NC}"

    CUDA_VISIBLE_DEVICES=$GPU_ID python -m vllm.entrypoints.openai.api_server \
        --model "$BASE_MODEL" \
        --host "$VLLM_HOST" \
        --port "$VLLM_PORT" \
        --enable-lora \
        --lora-modules "${LORA_NAME}=${LORA_PATH}" \
        --max-lora-rank "$LORA_RANK" \
        --max-loras 1 \
        --reasoning-parser qwen3 \
        --trust-remote-code > "$RESULT_DIR/vllm.log" 2>&1 &
    VLLM_PID=$!
    echo -e "  vLLM PID: ${VLLM_PID} (log: $RESULT_DIR/vllm.log)"

    local max_wait=600
    local waited=0
    while [ $waited -lt $max_wait ]; do
        if curl -s "http://localhost:${VLLM_PORT}/health" > /dev/null 2>&1; then
            echo -e "${GREEN}  vLLM server ready (${waited}s)${NC}"
            return 0
        fi
        if ! kill -0 $VLLM_PID 2>/dev/null; then
            echo -e "${RED}  vLLM server process died (see $RESULT_DIR/vllm.log)${NC}"
            return 1
        fi
        sleep 3
        waited=$((waited + 3))
    done

    echo -e "${RED}  vLLM server failed to start within ${max_wait}s${NC}"
    kill $VLLM_PID 2>/dev/null
    return 1
}

stop_vllm_server() {
    if [ -n "$VLLM_PID" ] && kill -0 $VLLM_PID 2>/dev/null; then
        echo -e "${YELLOW}Stopping vLLM server (PID: ${VLLM_PID})...${NC}"
        kill $VLLM_PID 2>/dev/null
        wait $VLLM_PID 2>/dev/null || true
        echo -e "${GREEN}  vLLM server stopped${NC}"
    fi
    VLLM_PID=""
}

trap stop_vllm_server EXIT INT TERM

OVERALL_START=$(date +%s)

echo -e "${BLUE}========================================${NC}"
echo -e "${BLUE}GRPO vs Base Eval — ${DATE}${NC}"
echo -e "${BLUE}========================================${NC}"
echo -e "GPU: ${GPU_ID} | vLLM port: ${VLLM_PORT}"
echo -e "Base: ${BASE_MODEL}"
echo -e "LoRA: ${LORA_NAME} -> ${LORA_PATH}"
echo -e "Data dir: ${DATA_DIR}"
echo -e "Result dir: ${RESULT_DIR}"
echo -e "Tasks (${#TASKS[@]}): ${TASKS[*]}"
echo ""

start_vllm_server
if [ $? -ne 0 ]; then
    echo -e "${RED}vLLM startup failed; aborting.${NC}"
    exit 1
fi

for MODEL in "${MODELS[@]}"; do
    MODEL_DIR_NAME="${MODEL//\//_}"
    LOG_DIR="$RESULT_DIR/$MODEL_DIR_NAME/log"
    mkdir -p "$LOG_DIR"

    echo -e "${BLUE}========================================${NC}"
    echo -e "${BLUE}Model: ${MODEL}${NC}"
    echo -e "${BLUE}========================================${NC}"

    MODEL_START=$(date +%s)
    SUCCESS_COUNT=0
    FAIL_COUNT=0
    SKIP_COUNT=0

    for task in "${TASKS[@]}"; do
        log_file="$LOG_DIR/${task}.log"
        data_file="$DATA_DIR/${task}.jsonl"

        if [ ! -f "$data_file" ]; then
            echo -e "${YELLOW}  [skip] $task — data file missing: $data_file${NC}"
            SKIP_COUNT=$((SKIP_COUNT + 1))
            continue
        fi

        echo -e "${YELLOW}>>> $task${NC}  (log: ${log_file})"
        echo "=== $(date '+%F %T') $task ===" >> "$log_file"

        set +e
        python evaluation/run.py \
            --model "$MODEL" \
            --model_router remote \
            --remote_url "$REMOTE_URL" \
            --gen-kwargs "$GEN_KWARGS" \
            --tasks "$task" \
            --data-dir "$DATA_DIR" \
            --output-dir "$RESULT_DIR" \
            --async --max-concurrent 5 2>&1 | tee -a "$log_file"
        rc=${PIPESTATUS[0]}
        set -e

        if [ $rc -eq 0 ]; then
            echo -e "${GREEN}  $task OK${NC}"
            SUCCESS_COUNT=$((SUCCESS_COUNT + 1))
        else
            echo -e "${RED}  $task FAILED (rc=$rc)${NC}"
            FAIL_COUNT=$((FAIL_COUNT + 1))
        fi
        echo ""
    done

    MODEL_END=$(date +%s)
    ELAPSED=$((MODEL_END - MODEL_START))
    echo -e "${BLUE}--- ${MODEL} Summary ---${NC}"
    echo -e "  ${GREEN}OK: ${SUCCESS_COUNT}${NC} / ${RED}Fail: ${FAIL_COUNT}${NC} / ${YELLOW}Skip: ${SKIP_COUNT}${NC}"
    echo -e "  Elapsed: $((ELAPSED / 60))m $((ELAPSED % 60))s"
    echo ""
done

OVERALL_END=$(date +%s)
OVERALL_ELAPSED=$((OVERALL_END - OVERALL_START))

echo -e "${BLUE}========================================${NC}"
echo -e "${BLUE}All Evaluations Completed${NC}"
echo -e "${BLUE}========================================${NC}"
echo -e "Total elapsed: $((OVERALL_ELAPSED / 60))m $((OVERALL_ELAPSED % 60))s"
echo -e "Results: $RESULT_DIR"
